import React from "react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";

const data = [
  { month: "T1", value: 180 },
  { month: "T2", value: 287 },
  { month: "T3", value: 215 },
  { month: "T4", value: 350 },
  { month: "T5", value: 290 },
  { month: "T6", value: 420 },
];

const CustomTooltip = ({ active, payload, label }) => {
  if (active && payload && payload.length) {
    return (
      <div
        style={{
          backgroundColor: "#fff",
          border: "1px solid #E5E7EB",
          borderRadius: 10,
          padding: "10px 16px",
          boxShadow: "0 4px 12px rgba(0,0,0,0.12)",
          fontSize: 13,
        }}
      >
        <div style={{ color: "#6B7280", marginBottom: 4, fontWeight: 500 }}>{label}</div>
        <div style={{ color: "#10B981", fontWeight: 700, fontSize: 16 }}>
          {payload[0].value} tr
        </div>
      </div>
    );
  }
  return null;
};

const GrowthChart = () => {
  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 16,
        padding: "24px 24px 16px",
        boxShadow: "0 1px 4px rgba(0,0,0,0.06), 0 2px 8px rgba(0,0,0,0.04)",
        border: "1px solid #F3F4F6",
        marginBottom: 20,
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 20,
        }}
      >
        <h3 style={{ fontSize: 16, fontWeight: 700, color: "#1F2937", margin: 0 }}>
          Tăng trưởng
        </h3>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 6,
            fontSize: 12,
            color: "#10B981",
            fontWeight: 600,
            background: "#D1FAE5",
            padding: "4px 10px",
            borderRadius: 20,
          }}
        >
          ↑ +24.5%
        </div>
      </div>

      <ResponsiveContainer width="100%" height={280}>
        <AreaChart data={data} margin={{ top: 10, right: 24, left: -10, bottom: 0 }}>
          <defs>
            <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#10B981" stopOpacity={0.25} />
              <stop offset="95%" stopColor="#10B981" stopOpacity={0.02} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#F3F4F6" vertical={false} />
          <XAxis
            dataKey="month"
            axisLine={false}
            tickLine={false}
            tick={{ fill: "#9CA3AF", fontSize: 12, fontWeight: 500 }}
          />
          <YAxis
            axisLine={false}
            tickLine={false}
            tick={{ fill: "#9CA3AF", fontSize: 12 }}
            tickFormatter={(v) => `${v}`}
            domain={[0, 500]}
          />
          <Tooltip content={<CustomTooltip />} cursor={{ stroke: "#10B981", strokeWidth: 1, strokeDasharray: "4 4" }} />
          <Area
            type="monotone"
            dataKey="value"
            stroke="#10B981"
            strokeWidth={2.5}
            fill="url(#colorValue)"
            dot={{ fill: "#10B981", strokeWidth: 0, r: 4 }}
            activeDot={{ r: 6, fill: "#10B981", stroke: "#fff", strokeWidth: 2 }}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default GrowthChart;

