import React, { useState } from "react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";
import { Select } from "antd";

const OPTIONS = {
  "doanh-thu": {
    label: "Doanh thu",
    color: "#10B981",
    data: [
      { month: "T1", value: 180 },
      { month: "T2", value: 287 },
      { month: "T3", value: 215 },
      { month: "T4", value: 350 },
      { month: "T5", value: 290 },
      { month: "T6", value: 420 },
    ],
    badgeText: "↑ +24.5%",
    badgeBg: "#D1FAE5",
    badgeColor: "#10B981",
  },
  "chi-phi": {
    label: "Chi phí",
    color: "#EF4444",
    data: [
      { month: "T1", value: 120 },
      { month: "T2", value: 180 },
      { month: "T3", value: 150 },
      { month: "T4", value: 220 },
      { month: "T5", value: 200 },
      { month: "T6", value: 280 },
    ],
    badgeText: "↑ +18.2%",
    badgeBg: "#FEE2E2",
    badgeColor: "#EF4444",
  },
  "loi-nhuan": {
    label: "Lợi nhuận",
    color: "#4169E1",
    data: [
      { month: "T1", value: 60 },
      { month: "T2", value: 107 },
      { month: "T3", value: 65 },
      { month: "T4", value: 130 },
      { month: "T5", value: 90 },
      { month: "T6", value: 140 },
    ],
    badgeText: "↑ +42.1%",
    badgeBg: "#DBEAFE",
    badgeColor: "#4169E1",
  },
  "cong-no": {
    label: "Công nợ",
    color: "#F59E0B",
    data: [
      { month: "T1", value: 300 },
      { month: "T2", value: 280 },
      { month: "T3", value: 320 },
      { month: "T4", value: 290 },
      { month: "T5", value: 350 },
      { month: "T6", value: 310 },
    ],
    badgeText: "↓ -8.3%",
    badgeBg: "#FEF3C7",
    badgeColor: "#F59E0B",
  },
};

const CustomTooltip = ({ active, payload, label, color }) => {
  if (active && payload && payload.length) {
    return (
      <div
        style={{
          backgroundColor: "#fff",
          border: "1px solid #E5E7EB",
          borderRadius: 10,
          padding: "10px 16px",
          boxShadow: "0 4px 12px rgba(0,0,0,0.12)",
          fontSize: 13,
        }}
      >
        <div style={{ color: "#6B7280", marginBottom: 4, fontWeight: 500 }}>{label}</div>
        <div style={{ color: color, fontWeight: 700, fontSize: 16 }}>
          {payload[0].value} tr
        </div>
      </div>
    );
  }
  return null;
};

const CustomTooltipWrapper = (props) => <CustomTooltip {...props} color={props.color} />;

const GrowthChart = () => {
  const [selected, setSelected] = useState("doanh-thu");
  const option = OPTIONS[selected];

  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 16,
        padding: "24px 24px 16px",
        boxShadow: "0 1px 4px rgba(0,0,0,0.06), 0 2px 8px rgba(0,0,0,0.04)",
        border: "1px solid #F3F4F6",
        marginBottom: 20,
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 20,
        }}
      >
        <h3 style={{ fontSize: 16, fontWeight: 700, color: "#1F2937", margin: 0 }}>
          Tăng trưởng
        </h3>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 6,
              fontSize: 12,
              color: option.badgeColor,
              fontWeight: 600,
              background: option.badgeBg,
              padding: "4px 10px",
              borderRadius: 20,
            }}
          >
            {option.badgeText}
          </div>
          <Select
            value={selected}
            onChange={setSelected}
            style={{ width: 120 }}
            size="small"
            options={[
              { value: "doanh-thu", label: "Doanh thu" },
              { value: "chi-phi", label: "Chi phí" },
              { value: "loi-nhuan", label: "Lợi nhuận" },
              { value: "cong-no", label: "Công nợ" },
            ]}
          />
        </div>
      </div>

      <ResponsiveContainer width="100%" height={280}>
        <AreaChart data={option.data} margin={{ top: 10, right: 24, left: -10, bottom: 0 }}>
          <defs>
            <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor={option.color} stopOpacity={0.25} />
              <stop offset="95%" stopColor={option.color} stopOpacity={0.02} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#F3F4F6" vertical={false} />
          <XAxis
            dataKey="month"
            axisLine={false}
            tickLine={false}
            tick={{ fill: "#9CA3AF", fontSize: 12, fontWeight: 500 }}
          />
          <YAxis
            axisLine={false}
            tickLine={false}
            tick={{ fill: "#9CA3AF", fontSize: 12 }}
            tickFormatter={(v) => `${v}`}
            domain={[0, 500]}
          />
          <Tooltip
            content={<CustomTooltip color={option.color} />}
            cursor={{ stroke: option.color, strokeWidth: 1, strokeDasharray: "4 4" }}
          />
          <Area
            type="monotone"
            dataKey="value"
            stroke={option.color}
            strokeWidth={2.5}
            fill="url(#colorValue)"
            dot={{ fill: option.color, strokeWidth: 0, r: 4 }}
            activeDot={{ r: 6, fill: option.color, stroke: "#fff", strokeWidth: 2 }}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default GrowthChart;
